  1	import { Text, TextContent, TextVariants } from '@patternfly/react-core';
  2	import * as React from 'react';
  3	import { useTranslation } from 'react-i18next';
  4	import { Filter, FilterDefinition, Filters } from '../../../model/filters';
  5	import { getCustomScopes } from '../../../model/scope';
  6	import { NodeData } from '../../../model/topology';
  7	import { createPeer } from '../../../utils/metrics';
  8	import { ElementField } from './element-field';
  9	
 10	export interface ElementFieldsProps {
 11	  id: string;
 12	  data: NodeData;
 13	  forceFirstAsText?: boolean;
 14	  filters: Filters;
 15	  setFilters: (filters: Filter[]) => void;
 16	  filterDefinitions: FilterDefinition[];
 17	}
 18	
 19	export const ElementFields: React.FC<ElementFieldsProps> = ({
 20	  id,
 21	  data,
 22	  forceFirstAsText,
 23	  filters,
 24	  setFilters,
 25	  filterDefinitions
 26	}) => {
 27	  const { t } = useTranslation('plugin__netobserv-plugin');
 28	
 29	  const fragments = [];
 30	  let forceAsText = forceFirstAsText;
 31	  let forceLabel = forceFirstAsText ? t('Name') : undefined;
 32	  if (data.peer.resource) {
 33	    fragments.push(
 34	      <ElementField
 35	        id={id + '-resource'}
 36	        key={id + '-resource'}
 37	        label={forceLabel || data.peer.resource.type}
 38	        forcedText={forceAsText ? data.peer.resource.name : undefined}
 39	        filters={filters}
 40	        filterType={'resource'}
 41	        peer={data.peer}
 42	        setFilters={setFilters}
 43	        filterDefinitions={filterDefinitions}
 44	      />
 45	    );
 46	    forceLabel = forceAsText = undefined;
 47	  }
 48	  if (data.peer.owner && data.peer.owner.type !== data.peer.resource?.type) {
 49	    fragments.push(
 50	      <ElementField
 51	        id={id + '-owner'}
 52	        key={id + '-owner'}
 53	        label={forceLabel || data.peer.owner.type}
 54	        forcedText={forceAsText ? data.peer.owner.name : undefined}
 55	        filters={filters}
 56	        filterType={'owner'}
 57	        peer={createPeer({ owner: data.peer.owner, namespace: data.peer.namespace })}
 58	        setFilters={setFilters}
 59	        filterDefinitions={filterDefinitions}
 60	      />
 61	    );
 62	    forceLabel = forceAsText = undefined;
 63	  }
 64	  // add available fields from custom scopes
 65	  getCustomScopes().forEach(sc => {
 66	    const value = data.peer[sc.id] as string | undefined;
 67	    if (value) {
 68	      fragments.push(
 69	        <ElementField
 70	          id={`${id}-${sc}`}
 71	          key={`${id}-${sc}`}
 72	          label={forceLabel || sc.name}
 73	          forcedText={forceAsText ? value : undefined}
 74	          filters={filters}
 75	          filterType={sc.id}
 76	          peer={createPeer({ [sc.id]: value })}
 77	          setFilters={setFilters}
 78	          filterDefinitions={filterDefinitions}
 79	        />
 80	      );
 81	      forceLabel = forceAsText = undefined;
 82	    }
 83	  });
 84	  if (data.peer.subnetLabel) {
 85	    fragments.push(
 86	      <ElementField
 87	        id={id + '-subnet-label'}
 88	        key={id + '-subnet-label'}
 89	        label={t('Subnet label')}
 90	        filters={filters}
 91	        filterType={'resource'}
 92	        peer={createPeer({ subnetLabel: data.peer.subnetLabel })}
 93	        setFilters={setFilters}
 94	        filterDefinitions={filterDefinitions}
 95	      />
 96	    );
 97	  }
 98	  if (data.peer.addr) {
 99	    fragments.push(
100	      <ElementField
101	        id={id + '-address'}
102	        key={id + '-address'}
103	        label={t('IP')}
104	        filters={filters}
105	        filterType={'resource'}
106	        peer={createPeer({ addr: data.peer.addr })}
107	        setFilters={setFilters}
108	        filterDefinitions={filterDefinitions}
109	      />
110	    );
111	  }
112	
113	  return (
114	    <>
115	      {fragments.length > 0 ? (
116	        fragments
117	      ) : (
118	        <TextContent id={id + '-no-infos'} className="record-field-container">
119	          {
120	            <Text component={TextVariants.p}>
121	              {t('No information available for this content. Decrease scope aggregation to get more details.')}
122	              <br />
123	              {t(
124	                'You may also configure subnet labels in the FlowCollector resource (spec.processor.subnetLabels) to identify IP ranges that are external to the cluster.'
125	              )}
126	            </Text>
127	          }
128	        </TextContent>
129	      )}
130	    </>
131	  );
132	};

